#Alignerimport numpy as npdef align_xy(sample_spectra, gcms_df):    """    Aligns X (Raman spectra) and Y (GC-MS data) based on common sample IDs for the ML model    Parameters:        sample_spectra (dict): Dictionary where keys are sample names and values are lists of spectra.                                This is the output of the load raman and preprocessing pipeline functions        gcms_df (pd.DataFrame): GC-MS data with sample IDs as the index.    Returns:        filtered_X (np.ndarray): Aligned X data (n_samples, n_features).        filtered_Y (np.ndarray): Aligned Y data (n_samples, n_targets).        filtered_sample_ids (list): List of aligned sample IDs.    """        X = []   #Initiate list for x-block    sample_ids = []  #initiate list to store sample IDs for alignment    for sample_id, spectra in sample_spectra.items():        spectral_data = np.array([spectrum.spectral_data for spectrum in spectra])  # Shape: (n_spectra, n_points)        X.append(spectral_data)  # Append spectral data                sample_ids.append(sample_id)  # Append sample ID                # Convert X to a NumPy array if it's a list    if isinstance(X, list):        X = np.vstack(X)  # Shape: (n_samples, n_features)        common_ids = set(sample_ids).intersection(set(gcms_df.index))    # Print IDs that could not be matched    unmatched_ids = set(sample_ids).symmetric_difference(set(gcms_df.index))    if unmatched_ids:        print(f"Could not match data for these IDs: {unmatched_ids}")    # Filter X and Y to keep only common IDs    filtered_X = []    filtered_sample_ids = []    for i, sample_id in enumerate(sample_ids):        if sample_id in common_ids:            filtered_X.append(X[i])            filtered_sample_ids.append(sample_id)        # Convert filtered_X to a NumPy array    filtered_X = np.vstack(filtered_X)  # Shape: (n_samples, n_features)     # Filter Y to keep only common IDs and convert to DataFrame    filtered_Y = gcms_df.loc[filtered_sample_ids]  # Shape: (n_samples, n_targets)       # Display the shapes of filtered X and Y     #print(f"Shape of filtered X: {filtered_X.shape}")    #print(f"Shape of filtered Y: {filtered_Y.shape}")        return filtered_X, filtered_Y, filtered_sample_ids,  